VALUES
  ('social-worker-moex-08090', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項是所謂的「社會性飽和」？', '["社會上分工愈來愈細，行職業類別多，造成「社會性飽和」", "現代科技進步愈來愈多人難以找到自己可以相信的東西，這種對世界與對自我的感受稱之為「社會性 飽和」", "三代同堂的家庭造成家庭成員人際溝通的複雜，稱之為「社會性飽和」", "捷運車廂裡擠滿了人，稱之為「社會性飽和」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08091', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據Jean Piaget的認知理論，人類與生俱來的認知過程中，以下列那兩項為最重要？', '["學習與適應", "智慧與組織", "適應與組織", "智慧與學習"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08092', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一個陳述不是混合家庭？', '["未婚生子的陳小姐與張先生組成家庭", "趙先生因案入監服刑，留下妻子和子女與趙先生父母同住", "因受暴而離婚的李小姐帶著兩名幼子與喪偶的郭先生結婚", "家裡有「爸爸的小孩，媽媽的小孩和爸媽的小孩」"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08093', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據艾瑞克森（Erikson）的觀點，青少年最重要任務為發展：', '["自我認同", "第一性徵", "批判性思考", "理性思考"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08094', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '張社工師針對受身體虐待的陳小妹妹深入的創傷治療，這是屬於那一層面的社會工作處遇？', '["鉅視層面", "居間層面", "微視層面", "中間層面"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08095', 'social-worker', 'social-worker-moex-098-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關人類行為與社會環境的陳述，那一個是錯誤的？', '["人類所處環境對其成長、發展有極大影響", "社會環境影響人類行為可以用系統理論來說明", "系統理論又稱為社會系統理論", "社會環境很大，所以人類行為不能影響社會環境"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:40+00:00", "source_pdf_sha1": "44ab37d668c4", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "6001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08096', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關英國1601年所制定的「伊莉莎白濟貧法案」（The Elizabeth Poor Law）之敘述，何者為非？', '["主要是以1536年的「亨利貧窮法案」及1572年的「教區分擔比例法案」為根據，為處理貧民救濟的主 要法規", "主張以教區來管理貧窮救濟，每一教區納稅人僅對該教區之貧民負責", "濟貧的經費主要是來自信徒的捐獻", "此濟貧法為貧窮兒童確立了學徒計畫，為依賴人口規劃工寮救貧院（workhouses）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08097', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '下列有關「睦鄰運動」（Settlement House Movement）的敘述，何者為非？', '["以居民需求作為工作的重點", "認為貧窮問題是個人的缺陷特質所致，因此必須從改造個人著手", "充分運用當地的民力", "工作者與服務對象相處在一起"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 2, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08098', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '以下有關珍‧亞當斯（Jane Addams）對後世社會工作貢獻之敘述，何者為非？', '["珍‧亞當斯（Jane Addams）女士受到湯恩比館工作理念的啟發，於1889年在美國芝加哥成立「赫爾館」 （Hull House）", "珍‧亞當斯（Jane Addams）對貧窮問題改採環境歸因", "工作取向採取3Rs，Research（研究）、Residence（與窮人共同生活）、Resilience（復原力）", "肯定各族群移民人口的差異與優勢"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08099', 'social-worker', 'social-worker-moex-098-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', 'Skidmore（2002）對社會工作本質有一些前提與假設，下列何者不符合此前提與假設？', '["社會工作與其他專業一樣，具有解決問題的功能", "社會工作實務是一種以科學與價值為基礎的藝術", "社會工作從事各種活動主要是考量成本效益來展現專業", "社會工作者本身即是專業助人的工具。因此，專業知識與價值的內化是社會工作者的特質"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "923bc3ad8521", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
